using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class CalendarTraining : TrainingContentBase
{
    public CalendarTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Calendar Overview",
            Slug = "calendar-overview",
            Summary = "What the Calendar module shows, how the three views work, how PO deliveries integrate, and how it connects to jobs.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/calendar"]""",
            Tags = """["calendar","scheduling","jobs"]""",
            ContentJson = """{"body":"## Calendar Overview\n\nThe Calendar module gives you a visual timeline of all jobs by their due dates, plus optional purchase order delivery dates. It is the go-to view when you need to see what is coming up, what is overdue, and how work is distributed across days, weeks, or months.\n\n### Three Views\n\nThe calendar offers three views — **Month**, **Week**, and **Day** — toggled with buttons in the header. Each view shows the same underlying data at a different zoom level.\n\n- **Month View** displays a traditional grid. Each cell shows the date number, up to three job chips, and an overflow count if there are more. Job chips are color-coded by their kanban stage and include priority icons for Critical and High priority work.\n- **Week View** shows seven columns with expanded job chips that include the customer name and additional detail. It is useful for planning the current or upcoming week.\n- **Day View** is a vertical list for a single date. Each job shows its full metadata: job number, title, priority, customer, stage, and assignee. An empty day shows an event_available icon and a message.\n\n### PO Deliveries Toggle\n\nThe header includes a PO Deliveries toggle button (local_shipping icon). When active, purchase order expected delivery dates appear on the calendar alongside jobs. Each PO event shows the PO number, vendor name, and line count. This helps you anticipate incoming materials and coordinate production around deliveries.\n\n### How Jobs Appear\n\nEach job chip shows:\n- The **job number** and **title**\n- A **left border** colored by the job's kanban stage color\n- **Priority icons**: a priority_high icon for Critical jobs and an arrow_upward icon for High priority jobs\n- An **overdue warning** icon when the due date has passed\n\n### Track Type Filtering\n\nA track type dropdown in the header lets you filter which kanban track's jobs are shown. This is useful when you have multiple tracks (Production, R&D, Maintenance) and want to focus on one.\n\n### Navigation\n\nPrevious and Next buttons (chevron_left / chevron_right) move backward and forward by one month, week, or day depending on the active view. The Today button snaps back to the current date. Clicking a date in Month or Week view switches to Day view for that date.\n\n### When to Use the Calendar\n\n- To see the week ahead and identify scheduling conflicts\n- To check which jobs are overdue at a glance\n- To correlate PO delivery dates with production schedules\n- To quickly jump to a specific day and review all work due\n- To filter by track type and focus on one area of the business","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Calendar — Guided Tour",
            Slug = "calendar-walkthrough",
            Summary = "A guided tour of the calendar page: view toggles, navigation, track type filter, PO deliveries toggle, and clicking dates.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/calendar"]""",
            Tags = """["calendar","walkthrough"]""",
            ContentJson = """{"appRoute":"/calendar","startButtonLabel":"Tour Calendar","steps":[{"element":".calendar-nav app-select","popover":{"title":"Track Type Filter","description":"Filter which jobs appear on the calendar by their kanban track type. Select a specific track (Production, R&D, Maintenance) to focus, or show all tracks at once.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Toggle Buttons","description":"Switch between Month, Week, and Day views. Month gives you the big picture, Week is great for planning the current sprint, and Day shows full detail for a single date.","side":"bottom"}},{"element":".month-label","popover":{"title":"Navigation Controls","description":"Use the left and right chevrons to move backward and forward by one period (month, week, or day depending on your current view). The Today button snaps back to the current date instantly.","side":"bottom"}},{"element":".calendar-nav .action-btn--sm:last-of-type","popover":{"title":"PO Deliveries Toggle","description":"Click to show or hide purchase order expected delivery dates on the calendar. When active (highlighted in primary color), PO events appear alongside job chips showing the PO number, vendor name, and line count. Great for coordinating production around incoming materials.","side":"bottom"}},{"element":".calendar-grid,.week-grid,.day-list","popover":{"title":"Calendar Content Area","description":"This is where jobs and PO deliveries are displayed. In Month view, click any date to switch to Day view for that date. In Week view, click a date header to jump to that day. Job chips are color-coded by stage and show priority icons for Critical and High priority work.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Calendar Field Reference",
            Slug = "calendar-field-reference",
            Summary = "Complete reference for every control, view mode, job chip element, PO event element, priority icon, and navigation behavior in the Calendar module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/calendar"]""",
            Tags = """["calendar","reference"]""",
            ContentJson = """{"title":"Calendar Field Reference","groups":[{"heading":"Header Controls","items":[{"label":"Track Type Filter","value":"Dropdown select. Filters jobs by kanban track type (Production, R&D/Tooling, Maintenance, Other, or custom tracks). Shows all tracks when no filter is selected."},{"label":"View Toggle — Month","value":"Button. Displays a traditional month grid with day cells. Each cell shows date number, up to 3 job chips, and a +N overflow count if more exist."},{"label":"View Toggle — Week","value":"Button. Displays a 7-column layout for the current week. Job chips show expanded detail including customer name."},{"label":"View Toggle — Day","value":"Button. Displays a single-date list view. Jobs show full metadata: job number, title, priority, customer, stage, assignee, and priority chip."},{"label":"Previous (chevron_left)","value":"Navigates backward by one period: one month in Month view, one week in Week view, one day in Day view."},{"label":"Next (chevron_right)","value":"Navigates forward by one period: one month in Month view, one week in Week view, one day in Day view."},{"label":"Period Label","value":"Displays the current period. Month view: month name and year (e.g., 'April 2026'). Week view: date range (e.g., 'Apr 13 – Apr 19, 2026'). Day view: full date (e.g., 'Thursday, April 16, 2026')."},{"label":"Today Button","value":"Resets the calendar to the current date. Available in all three views."},{"label":"PO Deliveries Toggle","value":"Button with local_shipping icon. When active, the button is highlighted in primary color and PO expected delivery dates appear on the calendar. When inactive, only jobs are shown."}]},{"heading":"Month View","items":[{"label":"Day Names Header","value":"Row showing abbreviated day names: Sun, Mon, Tue, Wed, Thu, Fri, Sat."},{"label":"Day Cell — Date Number","value":"Top-left of each cell. Today's date is highlighted with a colored background."},{"label":"Day Cell — Other Month Dates","value":"Dates outside the current month are grayed out (reduced opacity)."},{"label":"Day Cell — Job Chips","value":"Up to 3 job chips per cell. Each chip shows job number, truncated title, and optional priority/overdue icons. Left border colored by stage color."},{"label":"Day Cell — Overflow Count","value":"When more than 3 jobs exist on a date, a '+N more' label appears below the chips."},{"label":"Day Cell — PO Events","value":"When PO toggle is active, PO delivery events show with a local_shipping icon, PO number, and vendor name."},{"label":"Day Cell Click","value":"Clicking any day cell switches to Day view for that date."}]},{"heading":"Week View","items":[{"label":"Column Headers","value":"Seven columns showing day name and date number. Today's column header is highlighted."},{"label":"Job Chips (Expanded)","value":"Wider chips than Month view. Show: priority icon (if applicable), job number, overdue warning icon (if applicable), title, and customer name."},{"label":"PO Events","value":"Same as Month view — local_shipping icon + PO number + vendor name — when PO toggle is active."},{"label":"Date Header Click","value":"Clicking a column date header switches to Day view for that date."}]},{"heading":"Day View","items":[{"label":"Day Header","value":"Shows the full date, job count (e.g., '4 jobs'), and PO count (e.g., '2 deliveries') when PO toggle is active."},{"label":"Job Cards","value":"Expanded display: job number, title, priority icon, overdue warning icon. Below: meta row with customer name, stage name, assignee name, and priority chip."},{"label":"PO Deliveries Section","value":"Separate section below jobs. Each PO event shows PO number, vendor name, expected delivery date, status, and line count."},{"label":"Empty State","value":"When no jobs or PO events exist for the date, shows an event_available icon and an empty-state message."}]},{"heading":"Job Chip Elements","items":[{"label":"Job Number","value":"Displayed prominently (e.g., 'J-1055'). Identifies the job across the system."},{"label":"Title","value":"Job title text, truncated with ellipsis when space is limited."},{"label":"Stage Color (Left Border)","value":"A colored left border on each chip matching the job's current kanban stage color (stageColor from CalendarJob model)."},{"label":"Priority — Critical","value":"Icon: priority_high. Shown for jobs with Critical priority. Red/danger color."},{"label":"Priority — High","value":"Icon: arrow_upward. Shown for jobs with High priority. Orange/warning color."},{"label":"Overdue Warning","value":"Icon: warning. Shown when the job's due date has passed and it is still not complete."},{"label":"Customer Name","value":"Shown in Week and Day views. The customer associated with the job."},{"label":"Stage Name","value":"Shown in Day view meta row. The job's current kanban stage (e.g., 'In Production', 'QC/Review')."},{"label":"Assignee","value":"Shown in Day view meta row. The person assigned to the job (initials and color in some views)."}]},{"heading":"PO Event Elements","items":[{"label":"PO Number","value":"The purchase order number (e.g., 'PO-2048')."},{"label":"Vendor Name","value":"The vendor supplying the materials."},{"label":"Expected Delivery Date","value":"The date the PO is expected to arrive."},{"label":"Status","value":"The current PO status (e.g., 'Ordered', 'Shipped', 'Partially Received')."},{"label":"Line Count","value":"Number of line items on the PO. Shown in Day view."},{"label":"Icon","value":"local_shipping icon identifies PO events and distinguishes them from job chips."}]},{"heading":"Navigation Behavior","items":[{"label":"Month → Previous/Next","value":"Moves backward or forward by one calendar month."},{"label":"Week → Previous/Next","value":"Moves backward or forward by 7 days."},{"label":"Day → Previous/Next","value":"Moves backward or forward by 1 day."},{"label":"Today (any view)","value":"Resets to today's date in the current view mode."},{"label":"Date Click (Month/Week)","value":"Switches to Day view for the clicked date. Does not change the view toggle state permanently — you can switch back to Month or Week."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Calendar Knowledge Check",
            Slug = "calendar-quiz",
            Summary = "Test your knowledge of the Calendar module: views, navigation, PO deliveries, job chips, and filtering.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["calendar","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"cal1","text":"What are the three view modes available in the Calendar module?","options":[{"id":"a","text":"Month, Week, and Day","isCorrect":true},{"id":"b","text":"Timeline, Gantt, and List"},{"id":"c","text":"Daily, Quarterly, and Yearly"},{"id":"d","text":"Board, Table, and Calendar"}],"explanation":"The Calendar offers three views — Month, Week, and Day — toggled with buttons in the header. Each shows the same data at a different zoom level."},{"id":"cal2","text":"You want to see purchase order expected delivery dates alongside your jobs on the calendar. How do you enable this?","options":[{"id":"a","text":"Go to Admin → Calendar Settings and check 'Show PO Deliveries'"},{"id":"b","text":"Click the PO Deliveries toggle button (local_shipping icon) in the calendar header","isCorrect":true},{"id":"c","text":"Switch to the Purchase Orders page and enable calendar view"},{"id":"d","text":"PO deliveries are always shown — they cannot be toggled off"}],"explanation":"The PO Deliveries toggle in the header controls whether purchase order delivery dates appear on the calendar. When active, the button is highlighted in the primary color."},{"id":"cal3","text":"In Month view, a day cell shows '3 job chips and +4 more'. What does the '+4 more' label mean?","options":[{"id":"a","text":"4 jobs were recently archived from that date"},{"id":"b","text":"4 additional jobs are due on that date but are hidden to save space","isCorrect":true},{"id":"c","text":"4 PO deliveries are expected on that date"},{"id":"d","text":"The jobs have been there for 4 or more days past their due date"}],"explanation":"Month view shows up to 3 job chips per day cell. When more jobs exist, a '+N more' overflow count appears. Click the day to switch to Day view and see all jobs."},{"id":"cal4","text":"What does a priority_high icon on a job chip indicate?","options":[{"id":"a","text":"The job is High priority"},{"id":"b","text":"The job is Critical priority","isCorrect":true},{"id":"c","text":"The job is overdue"},{"id":"d","text":"The job has been flagged for review"}],"explanation":"The priority_high icon indicates Critical priority. High priority jobs use the arrow_upward icon instead. Both help you quickly spot important work on the calendar."},{"id":"cal5","text":"You are in Week view and want to see full details for Wednesday's jobs. How do you navigate there?","options":[{"id":"a","text":"Double-click on Wednesday's column to expand it"},{"id":"b","text":"Click Wednesday's date header to switch to Day view for that date","isCorrect":true},{"id":"c","text":"Hover over Wednesday's column to see a tooltip with job details"},{"id":"d","text":"Right-click and select 'View Day Details'"}],"explanation":"Clicking a date header in Week view (or a day cell in Month view) switches to Day view for that date, showing full job details including customer, stage, assignee, and priority."},{"id":"cal6","text":"What does the colored left border on a job chip represent?","options":[{"id":"a","text":"The job's priority level (red = Critical, orange = High, etc.)"},{"id":"b","text":"The job's kanban stage color","isCorrect":true},{"id":"c","text":"The track type color for the job's board"},{"id":"d","text":"The customer's assigned color"}],"explanation":"Each job chip has a left border colored by its kanban stage color (stageColor). This lets you visually identify which stage a job is in without reading the text."},{"id":"cal7","text":"You see a warning icon on a job chip. What does this mean?","options":[{"id":"a","text":"The job has unresolved quality issues"},{"id":"b","text":"The job's due date has passed and it is still not complete","isCorrect":true},{"id":"c","text":"The job is missing required materials"},{"id":"d","text":"The job has no assignee"}],"explanation":"The warning icon appears on jobs that are overdue — their due date has passed but they have not been completed. This helps you quickly spot late work on the calendar."},{"id":"cal8","text":"How does the Track Type filter in the calendar header work?","options":[{"id":"a","text":"It filters which kanban track's jobs are shown on the calendar","isCorrect":true},{"id":"b","text":"It changes the calendar color theme to match the track type"},{"id":"c","text":"It switches between different calendar layouts"},{"id":"d","text":"It filters PO deliveries by the vendor's track assignment"}],"explanation":"The track type dropdown filters jobs by their kanban track type (Production, R&D, Maintenance, etc.). This lets you focus on one area of the business when planning."},{"id":"cal9","text":"In Day view, what information is shown in a job's meta row?","options":[{"id":"a","text":"Created date, last modified date, and file attachment count"},{"id":"b","text":"Customer name, stage name, assignee name, and priority chip","isCorrect":true},{"id":"c","text":"Job cost estimate, hours logged, and completion percentage"},{"id":"d","text":"Part number, quantity ordered, and material type"}],"explanation":"Day view shows the most detail. Each job displays its number, title, and priority icon on the main line, with a meta row below showing customer name, current stage, assigned person, and a priority chip."},{"id":"cal10","text":"What happens when you click the Today button?","options":[{"id":"a","text":"It creates a new job due today"},{"id":"b","text":"It resets the calendar to the current date in whichever view is active","isCorrect":true},{"id":"c","text":"It switches to Day view for today"},{"id":"d","text":"It highlights all overdue jobs across the entire calendar"}],"explanation":"The Today button resets the calendar to the current date while keeping your current view mode (Month, Week, or Day). It does not change the active view — just the date focus."},{"id":"cal11","text":"In the Day view, when no jobs or PO events exist for the selected date, what is displayed?","options":[{"id":"a","text":"A blank white space with no indicators"},{"id":"b","text":"An event_available icon and an empty-state message","isCorrect":true},{"id":"c","text":"A suggestion to create a new job for that date"},{"id":"d","text":"A list of recently completed jobs from nearby dates"}],"explanation":"Empty days in Day view show an empty state with the event_available icon and a message indicating no work is scheduled. This follows the app-wide pattern of showing meaningful empty states rather than blank space."},{"id":"cal12","text":"A PO event on the calendar shows 'PO-2048 · Acme Metals · 5 lines'. What does '5 lines' represent?","options":[{"id":"a","text":"The PO has 5 separate delivery dates"},{"id":"b","text":"The PO contains 5 line items","isCorrect":true},{"id":"c","text":"The PO has been revised 5 times"},{"id":"d","text":"5 units are expected in this delivery"}],"explanation":"The line count on a PO calendar event shows how many line items are on the purchase order. This gives you a quick sense of the delivery's scope without opening the full PO detail."}]}"""
        });

        Log.Information("Seeded Calendar training modules");
    }
}
